  ('half-kneeling-start-sprint', 'Half-kneeling start to 3 yards or step-out only.', 'No default sex-based adjustment. Scale by acceleration skill, power, body control, deceleration ability, and injury history rather than gender alone.'),
  ('push-up-prone-start-sprint', 'Use tall plank start to 3 yards, not full prone.', 'No default sex-based adjustment. Scale by acceleration skill, power, body control, deceleration ability, and injury history rather than gender alone.'),
  ('lateral-start-to-sprint-breakout', 'Side step to jog breakout, not max sprint.', 'No default sex-based adjustment. Scale by acceleration skill, power, body control, deceleration ability, and injury history rather than gender alone.'),
  ('backpedal-to-sprint-turn', 'Backpedal walk to turn and jog.', 'No default sex-based adjustment. Scale by acceleration skill, power, body control, deceleration ability, and injury history rather than gender alone.'),
  ('partner-chase-acceleration', 'No-contact chase jog or tag-to-cone at low speed.', 'No default sex-based adjustment. Scale by acceleration skill, power, body control, deceleration ability, and injury history rather than gender alone.'),
  ('light-sled-sprint-band-resisted-acceleration', 'Usually avoid sled/band sprint; use unloaded acceleration first.', 'No default sex-based adjustment. Scale by acceleration skill, power, body control, deceleration ability, and injury history rather than gender alone.'),
  ('low-incline-hill-sprint-acceleration', 'Low hill run at submaximal speed, 5 yards.', 'No default sex-based adjustment. Scale by acceleration skill, power, body control, deceleration ability, and injury history rather than gender alone.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
