-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Express acceleration speed while fresh — low volume, high intent, generous rest.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('falling-start-to-5-10-yard-sprint', 'The falling start teaches the athlete to project forward from a whole-body lean rather than bending at the waist or popping straight upward. Overtime Athletes describes falling starts as a way to teach the strong lean position used during sprint acceleration, with the athlete keeping the body straight as they fall forward and then driving out as they catch themselves.', 'Belongs in acceleration_start (311) — primary Output acceleration entry using whole-body lean and first-step projection after Skill falling-start posture work.', 'First Output acceleration rep in the block after Skill falling-start position work; before two-point or three-point starts when lean and catch mechanics are established.', 'Acceleration Output belongs while the athlete is fresh — short distance, high intent, generous rest, crisp mechanics. Do not program daily, stack after HIIT or high-volume lower-body Capacity, use short rest, or chase volume when speed drops. Quality beats rep count. Do not use when athlete is only practicing lean mechanics — classify as Skill. If speed drops rep to rep, stop the set.', 'Regress to falling-position hold or 3–5 yards at 70–85% intent; progress to timed or competitive reps when catch and decel are clean. Hypermobility athletes need clean ankle/knee/hip alignment before high intent.'),
  ('two-point-start-to-5-10-yard-sprint', 'The two-point start is a practical athletic start for field, court, and general speed athletes. NSCA describes two-point starts as using a comfortable staggered stance, weight shifted over the lead leg, elbows bent, and a forward body position before moving forcefully.', 'Belongs in acceleration_start (311) — foundational Output acceleration drill after Skill two-point walk-in entry.', 'Core Output acceleration drill after Skill two-point walk-in work; early in acceleration block before three-point or start variations.', 'Acceleration Output belongs while the athlete is fresh — short distance, high intent, generous rest, crisp mechanics. Do not program daily, stack after HIIT or high-volume lower-body Capacity, use short rest, or chase volume when speed drops. Quality beats rep count. Skill version is walk-in, freeze, or first-step rehearsal — do not confuse submax walk-ins with Output reps.', 'Regress to two-point walk-in or 3–5 yard submax; progress to timed 5/10-yard splits when mechanics are clean. Hypermobility athletes need strong foot/knee alignment before maximal intent.'),
  ('three-point-start-acceleration', 'The three-point start lowers the athlete closer to a sprint-start position and can increase projection demand. It is more technically demanding than a two-point start because the athlete must coordinate the ground hand, hip height, shin angles, arm action, and first step without collapsing. NSCA''s sprint mechanics framework separates starting and acceleration as trainable technical areas, and this card belongs at the high-intent end of that start progression.', 'Belongs in acceleration_start (311) — advanced start variation requiring two-point competency and adequate wrist/shoulder/hip setup.', 'After two-point Output starts when athlete shows clean staggered stance and can hold a still set; not before two-point mastery.', 'Acceleration Output belongs while the athlete is fresh — short distance, high intent, generous rest, crisp mechanics. Do not program daily, stack after HIIT or high-volume lower-body Capacity, use short rest, or chase volume when speed drops. Quality beats rep count. Do not assign to beginners or athletes who cannot hold a still set. Wrist pain means stop immediately.', 'Regress to two-point start or three-point setup hold; progress to timed starts when set position and first step are consistent. Hypermobility athletes need active joint control in wrist, shoulder, hip, knee, and ankle.'),
  ('half-kneeling-start-sprint', 'The half-kneeling start places the athlete in a low start position and emphasizes front-leg loading, torso angle, and horizontal projection. The Prehab Guys describe half-kneeling to sprint as starting with one foot flat and the other knee on the ground, then pushing into the ground, shifting weight to the front leg, and beginning a sprinting motion. Overtime Athletes similarly emphasizes front-knee drive over the toe, torso lean, and horizontal drive from the half-kneeling start.', 'Belongs in start_variation (312) — low-position Output start emphasizing front-leg drive and horizontal projection.', 'Mid acceleration block as a start variation after two-point starts; when athlete needs low-position projection without three-point stance.', 'Acceleration Output belongs while the athlete is fresh — short distance, high intent, generous rest, crisp mechanics. Do not program daily, stack after HIIT or high-volume lower-body Capacity, use short rest, or chase volume when speed drops. Quality beats rep count. Do not use with painful kneeling or when athlete pops straight up before sprinting.', 'Regress to half-kneeling step-out or 3-yard sprint; alternate lead legs when pain-free. Hypermobility athletes need front-foot tripod and knee tracking cues.'),
  ('push-up-prone-start-sprint', 'The push-up/prone start challenges the athlete to rapidly reorganize from the ground into an acceleration pattern. King Sports describes the push-up start as beginning from the bottom of a push-up position, pushing up while bringing the dominant foot underneath the body, and emphasizing quick turnover, timing, and balance.', 'Belongs in start_variation (312) — high-coordination ground-to-sprint transition requiring clean rise from floor.', 'Late in start_variation block when athlete can rise from ground cleanly; after standing starts are established.', 'Acceleration Output belongs while the athlete is fresh — short distance, high intent, generous rest, crisp mechanics. Do not program daily, stack after HIIT or high-volume lower-body Capacity, use short rest, or chase volume when speed drops. Quality beats rep count. Do not use with wrist/shoulder/low-back pain or when athlete stands tall before sprinting. Prone position inappropriate for pregnancy/postpartum.', 'Regress to tall plank start to 3 yards; progress to prone start on visual/auditory cue. Hypermobility athletes need strong shoulder, wrist, and trunk control.'),
  ('lateral-start-to-sprint-breakout', 'This drill bridges lateral movement skill into true acceleration. It requires a lateral push, hip turn, reorientation of the torso, and then an aggressive sprint. It should come after the athlete has demonstrated clean lateral shuffle mechanics and basic two-point acceleration. Since NSCA defines agility/change-of-direction work as involving movement execution and decision-making, this drill can progress either toward COD Output or reactive agility depending on whether a cue is added.', 'Belongs in multidirectional_start (313) — lateral-to-linear acceleration breakout after linear start competency.', 'After linear acceleration starts when athlete has clean lateral shuffle mechanics; early in multidirectional start block.', 'Acceleration Output belongs while the athlete is fresh — short distance, high intent, generous rest, crisp mechanics. Do not program daily, stack after HIIT or high-volume lower-body Capacity, use short rest, or chase volume when speed drops. Quality beats rep count. Do not use when lateral push causes knee valgus or athlete spins instead of turning efficiently.', 'Regress to side step to jog breakout; progress to visual cue or partner chase. Hypermobility athletes need knee/ankle control and hip stability before speed.'),
  ('backpedal-to-sprint-turn', 'Backpedal-to-sprint trains a common sport transition: moving backward while tracking space, then turning and accelerating forward. TrainAdapt describes backpedal sprints as backpedaling 5–10 yards under control with chest up and short steps, then planting and exploding forward into a sprint. Jr. NBA''s backpedal-slide-sprint drill also presents backpedal-to-sprint as a footwork pattern for practicing different movement directions.', 'Belongs in multidirectional_start (313) — backward-to-forward transition requiring backpedal skill and safe breakout space.', 'After lateral breakout when athlete shows controlled backpedal; requires clear backward and forward lanes.', 'Acceleration Output belongs while the athlete is fresh — short distance, high intent, generous rest, crisp mechanics. Do not program daily, stack after HIIT or high-volume lower-body Capacity, use short rest, or chase volume when speed drops. Quality beats rep count. Skill version is walkthrough; Output version is fast breakout. Do not use without clear backward lane.', 'Regress to backpedal walk to turn and jog; progress to coach cue or competitive chase. Hypermobility athletes need plant control and knee tracking.'),
  ('partner-chase-acceleration', 'The chase element raises intent and creates a simple perception-action demand: react to another athlete and accelerate with urgency. SimpliFaster''s start-variation discussion emphasizes that sport acceleration often starts from chaotic and varied positions, and chase starts are one way to add more game-like urgency after technical mechanics have been learned.', 'Belongs in chase_acceleration (314) — competitive high-intent acceleration after clean mechanics; requires group supervision.', 'Late in acceleration block when mechanics are clean and intent needs raising; requires supervised pairing and clear lanes.', 'Acceleration Output belongs while the athlete is fresh — short distance, high intent, generous rest, crisp mechanics. Do not program daily, stack after HIIT or high-volume lower-body Capacity, use short rest, or chase volume when speed drops. Quality beats rep count. Can become chaotic if pairing, lane setup, and rules are poor. Do not run repeated races with short rest.', 'Pair by speed, size, maturity, and control rather than gender alone. Hypermobility athletes need mechanics and stopping control before competitive reps.'),
  ('light-sled-sprint-band-resisted-acceleration', 'Resisted sprinting can overload horizontal force application during acceleration. NSCA summarizes sled-pull sprint work as a method for affecting sprint force-velocity qualities in high school athletes, and an NSCA team-sport example describes 10–15 yard sled-resisted sprints with generous rest as acceleration-oriented work.', 'Belongs in resisted_acceleration (315) — horizontal force overload when unresisted acceleration mechanics are established.', 'After unresisted acceleration starts when mechanics are sound; before or paired with unresisted contrast reps in same session.', 'Acceleration Output belongs while the athlete is fresh — short distance, high intent, generous rest, crisp mechanics. Do not program daily, stack after HIIT or high-volume lower-body Capacity, use short rest, or chase volume when speed drops. Quality beats rep count. Too heavy becomes strength grind or alters sprinting. Do not use before athlete can sprint well unloaded.', 'Light resistance only — athlete should maintain sprint rhythm. Scale load by speed preservation and mechanics, not body mass alone. Hypermobility athletes need trunk and hip control under resistance.'),
  ('low-incline-hill-sprint-acceleration', 'Hill sprints can provide an acceleration-specific overload because the incline naturally encourages forward lean and increases lower-body drive demands. Sportsmith describes hill sprints as a common alternative stimulus for acceleration, noting that the incline overloads hip and knee extensors and that gravity acts as an external resistance similar in some ways to sled towing.', 'Belongs in hill_acceleration (316) — incline acceleration variation when safe low-grade surface is available.', 'Acceleration variation when safe low incline is available; after unresisted starts or as contrast with sled work.', 'Acceleration Output belongs while the athlete is fresh — short distance, high intent, generous rest, crisp mechanics. Do not program daily, stack after HIIT or high-volume lower-body Capacity, use short rest, or chase volume when speed drops. Quality beats rep count. Too steep or too long becomes conditioning or strength endurance. Do not use on slippery surfaces or with Achilles/calf pain.', 'Use shallow incline and limit reps for beginners; progress to 10–15 yard timed starts. Hypermobility athletes need foot/ankle stiffness and knee tracking uphill.')
) AS v(slug, why_works, why_here, best_placement, misuse, scale_guidance)
JOIN coaching.exercise e ON e.slug = v.slug
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_works = EXCLUDED.why_it_works,
  why_it_goes_here = EXCLUDED.why_it_goes_here,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  scaling_guidance = EXCLUDED.scaling_guidance,
  updated_at = now();

-- Acceleration-cluster validation education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'output_acceleration_readiness',
  NULL,
  'Acceleration Output without fatigue',
  'Short, high-intent acceleration reps express speed while fresh — not after conditioning, with short rest, or when mechanics degrade.',
  'Acceleration & Start Speed Output cards (1–10) turn sprint mechanics from Skill into real speed expression: falling starts, two/three-point starts, start variations, multidirectional breakouts, chase accelerations, resisted sprints, and hill accelerations.',
  'NSCA treats acceleration as a distinct technical/performance area. True high-intensity sprinting at 95–100% often needs 48–72+ hours between hard exposures. These cards improve speed, not fatigue tolerance.',
  'Keep distance short (5–15 yards), reps low (2–6), rest generous (60–90s+), intent high, and mechanics crisp. Stop when speed drops. Classify walk-in or submax starts as Skill; repeated fatigued reps as Fitness.',
  'Do not program daily acceleration Output, stack after HIIT or high-volume lower-body Capacity, use three-point or prone starts for beginners, chase volume when speed drops, or skip deceleration prerequisites.'
)
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
